import React from 'react';
import { graphql } from 'gatsby';
import { GatsbyImage } from 'gatsby-plugin-image';
import Layout from '../../components/layout';
import SectionMenu from '../../components/sections/menu';
import Grid from '@mui/material/Grid';
import Box from '@mui/material/Box';

export default function WorksTemplate(props) {
  const { data, params } = props;

  const { markdownRemark } = data; // data.markdownRemark holds your post data
  const { frontmatter, html } = markdownRemark;

  console.log(props);

  const images = data.allFile.edges
    .filter(
      edge =>
        edge.node.relativeDirectory === `works/${params.frontmatter__slug}`
    )
    .map(edge => edge.node.childImageSharp.gatsbyImageData);

  console.log(images);

  return (
    <Layout>
      <SectionMenu />
      <Grid
        container
        direction='row'
        justifyContent='center'
        spacing={4}
        mt={6} // spacing 分を引く
      >
        {images.map((image, i) => {
          return (
            <Grid item xs={12} key={i}>
              <Box>
                <GatsbyImage image={image} alt={`image-${i}`} />
              </Box>
            </Grid>
          );
        })}
        <Grid item xs={12}>
          <div dangerouslySetInnerHTML={{ __html: html }} />
        </Grid>
      </Grid>
    </Layout>
  );
}

export const pageQuery = graphql`
  query ($id: String!) {
    markdownRemark(id: { eq: $id }) {
      html
      frontmatter {
        date(formatString: "MMMM DD, YYYY")
        slug
      }
    }
    allFile(
      sort: { relativePath: ASC }
      filter: { relativeDirectory: { glob: "works/*" } }
    ) {
      edges {
        node {
          relativeDirectory
          childImageSharp {
            gatsbyImageData(width: 1920)
          }
        }
      }
    }
  }
`;
